import { prisma } from "@/lib/prisma";

// No MVP ainda não temos login: assumimos o primeiro escritório como o
// "tenant" da sessão. Quando a auth entrar (Fase 1), trocamos isto pelo
// escritório do usuário logado — o resto das queries já filtra por ele.
export async function getEscritorioAtual() {
  return prisma.escritorio.findFirst({ orderBy: { criadoEm: "asc" } });
}

function inicioDoDia(d = new Date()): Date {
  const x = new Date(d);
  x.setHours(0, 0, 0, 0);
  return x;
}

export async function getDadosPainel(escritorioId: string) {
  const hoje = inicioDoDia();
  const em7Dias = new Date(hoje);
  em7Dias.setDate(em7Dias.getDate() + 7);
  const fimDoMes = new Date(hoje.getFullYear(), hoje.getMonth() + 1, 0, 23, 59, 59);

  const [prazosSemana, prazosUrgentes, casosAtivos, audienciasMes, casosRecentes] =
    await Promise.all([
      // Contagem de prazos não concluídos vencendo nos próximos 7 dias.
      prisma.prazo.count({
        where: {
          concluido: false,
          vencimento: { gte: hoje, lte: em7Dias },
          caso: { escritorioId },
        },
      }),
      // Lista detalhada dos próximos prazos, com o caso e o cliente.
      prisma.prazo.findMany({
        where: {
          concluido: false,
          vencimento: { gte: hoje },
          caso: { escritorioId },
        },
        orderBy: { vencimento: "asc" },
        take: 5,
        include: { caso: { include: { cliente: true } } },
      }),
      prisma.caso.count({
        where: { escritorioId, status: { in: ["ATIVO", "AGUARDANDO"] } },
      }),
      prisma.prazo.count({
        where: {
          tipo: "AUDIENCIA",
          vencimento: { gte: hoje, lte: fimDoMes },
          caso: { escritorioId },
        },
      }),
      prisma.caso.findMany({
        where: { escritorioId },
        orderBy: { criadoEm: "desc" },
        take: 5,
        include: { cliente: true },
      }),
    ]);

  return { prazosSemana, prazosUrgentes, casosAtivos, audienciasMes, casosRecentes };
}

// Quantos dias faltam até o vencimento (0 = hoje, negativo = atrasado).
export function diasAte(vencimento: Date): number {
  const hoje = inicioDoDia();
  const alvo = inicioDoDia(vencimento);
  return Math.round((alvo.getTime() - hoje.getTime()) / 86_400_000);
}

export function rotuloPrazo(dias: number): string {
  if (dias < 0) return `${Math.abs(dias)}d atrasado`;
  if (dias === 0) return "Hoje";
  if (dias === 1) return "Amanhã";
  return `${dias} dias`;
}

// Cor do badge conforme urgência.
export function urgenciaPrazo(dias: number): "danger" | "warning" | "normal" {
  if (dias <= 0) return "danger";
  if (dias <= 3) return "warning";
  return "normal";
}
