import {
  getEscritorioAtual,
  getDadosPainel,
  diasAte,
  rotuloPrazo,
  urgenciaPrazo,
} from "@/lib/dashboard";

// Sempre renderiza no request (dados mudam o tempo todo no painel).
export const dynamic = "force-dynamic";

const badgeCores: Record<string, string> = {
  danger: "bg-red-50 text-red-700 ring-red-600/10",
  warning: "bg-amber-50 text-amber-700 ring-amber-600/10",
  normal: "bg-slate-50 text-slate-600 ring-slate-500/10",
};

const areaCores: Record<string, string> = {
  Trabalhista: "bg-indigo-50 text-indigo-700",
  Cível: "bg-emerald-50 text-emerald-700",
  Tributário: "bg-amber-50 text-amber-700",
};

function iniciais(nome: string): string {
  return nome
    .split(" ")
    .filter(Boolean)
    .slice(0, 2)
    .map((p) => p[0])
    .join("")
    .toUpperCase();
}

export default async function PainelPage() {
  const escritorio = await getEscritorioAtual();

  if (!escritorio) {
    return (
      <main className="mx-auto max-w-2xl px-6 py-24 text-center">
        <h1 className="text-2xl font-medium text-slate-800">Lexo</h1>
        <p className="mt-3 text-slate-500">
          Nenhum escritório cadastrado ainda. Rode{" "}
          <code className="rounded bg-slate-100 px-1.5 py-0.5 text-sm">npm run db:seed</code>{" "}
          para popular dados de demonstração.
        </p>
      </main>
    );
  }

  const { prazosSemana, prazosUrgentes, casosAtivos, audienciasMes, casosRecentes } =
    await getDadosPainel(escritorio.id);

  const hojeFmt = new Intl.DateTimeFormat("pt-BR", {
    weekday: "long",
    day: "2-digit",
    month: "long",
    year: "numeric",
  }).format(new Date());

  const metricas = [
    { rotulo: "Prazos esta semana", valor: prazosSemana, cor: prazosSemana > 0 ? "text-red-600" : "text-slate-800" },
    { rotulo: "Processos ativos", valor: casosAtivos, cor: "text-slate-800" },
    { rotulo: "Audiências no mês", valor: audienciasMes, cor: "text-slate-800" },
    { rotulo: "Honorários a receber", valor: "R$ 48k", cor: "text-emerald-600" },
  ];

  return (
    <main className="mx-auto max-w-5xl px-6 py-8">
      {/* Cabeçalho */}
      <header className="mb-6 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-indigo-600 text-lg font-semibold text-white">
            L
          </div>
          <div>
            <p className="font-medium text-slate-800">
              Lexo{" "}
              <span className="text-sm font-normal text-slate-400">/ {escritorio.nome}</span>
            </p>
            <p className="text-sm capitalize text-slate-500">{hojeFmt}</p>
          </div>
        </div>
        <span className="rounded-full bg-slate-100 px-3 py-1 text-sm text-slate-600">
          {prazosUrgentes.length} alertas
        </span>
      </header>

      {/* Métricas */}
      <section className="mb-6 grid grid-cols-2 gap-3 sm:grid-cols-4">
        {metricas.map((m) => (
          <div key={m.rotulo} className="rounded-lg bg-slate-50 p-4">
            <p className="text-sm text-slate-500">{m.rotulo}</p>
            <p className={`mt-1 text-2xl font-medium ${m.cor}`}>{m.valor}</p>
          </div>
        ))}
      </section>

      <div className="grid gap-4 lg:grid-cols-2">
        {/* Prazos urgentes */}
        <section className="rounded-xl border border-slate-200 bg-white p-5">
          <h2 className="mb-3 flex items-center gap-2 font-medium text-slate-800">
            <span className="text-red-500">⏰</span> Prazos urgentes
          </h2>
          {prazosUrgentes.length === 0 ? (
            <p className="py-6 text-center text-sm text-slate-400">Nenhum prazo pendente. 🎉</p>
          ) : (
            <ul className="divide-y divide-slate-100">
              {prazosUrgentes.map((prazo) => {
                const dias = diasAte(prazo.vencimento);
                const urg = urgenciaPrazo(dias);
                return (
                  <li key={prazo.id} className="flex items-center justify-between py-2.5">
                    <div>
                      <p className="text-sm text-slate-800">
                        {prazo.descricao} — {prazo.caso.titulo}
                      </p>
                      <p className="mt-0.5 text-xs text-slate-500">
                        {prazo.caso.numeroProcesso ?? prazo.caso.cliente.nome}
                      </p>
                    </div>
                    <span
                      className={`shrink-0 rounded-md px-2.5 py-1 text-xs ring-1 ring-inset ${badgeCores[urg]}`}
                    >
                      {rotuloPrazo(dias)}
                    </span>
                  </li>
                );
              })}
            </ul>
          )}
        </section>

        {/* Casos recentes */}
        <section className="rounded-xl border border-slate-200 bg-white p-5">
          <h2 className="mb-3 flex items-center gap-2 font-medium text-slate-800">
            <span className="text-indigo-500">📁</span> Casos recentes
          </h2>
          <ul className="divide-y divide-slate-100">
            {casosRecentes.map((caso) => (
              <li key={caso.id} className="flex items-center gap-3 py-2.5">
                <div
                  className={`flex h-8 w-8 items-center justify-center rounded-full text-xs font-medium ${
                    areaCores[caso.area] ?? "bg-slate-100 text-slate-600"
                  }`}
                >
                  {iniciais(caso.cliente.nome)}
                </div>
                <div className="min-w-0 flex-1">
                  <p className="truncate text-sm text-slate-800">{caso.cliente.nome}</p>
                  <p className="text-xs text-slate-500">
                    {caso.area} · {caso.status.toLowerCase()}
                  </p>
                </div>
              </li>
            ))}
          </ul>
        </section>
      </div>

      <p className="mt-6 text-center text-xs text-slate-400">
        Lexo · MVP — dados reais do banco (SQLite via Prisma)
      </p>
    </main>
  );
}
